using namespace std;

int main() {
    // Step 1: Declare and Initialize a 2D array
    int matrix[3][3] = {
        {1, 2, 3},  // First row
        {4, 5, 6},  // Second row
        {7, 8, 9}   // Third row
    };

    // Step 2: Row-major traversal
    cout << "Row-major Order:" << endl;
    for (int i = 0; i < 3; i++) {  // Iterate rows
        for (int j = 0; j < 3; j++) {  // Iterate columns
            cout << matrix[i][j] << " ";  
        }
        cout << endl;
    }

    // Step 3: Column-major traversal
    cout << "Column-major Order:" << endl;
    for (int j = 0; j < 3; j++) {  // Iterate columns
        for (int i = 0; i < 3; i++) {  // Iterate rows
            cout << matrix[i][j] << " ";  
        }
        cout << endl;
    }

    return 0;
}
```

**Expected Output:**

```default
Row-major Order:
1 2 3 
4 5 6 
7 8 9 

Column-major Order:
1 4 7 
2 5 8 
3 6 9 
```

